package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"net/http"
	"strconv"
	"strings"
)

// User represents an authenticated user stored in the request context.
type User struct {
	ID   int64  `json:"id"`
	Role string `json:"role"`
}

// Order represents an order record from the database.
type Order struct {
	ID     int64   `json:"id"`
	UserID int64   `json:"user_id"`
	Item   string  `json:"item"`
	Amount float64 `json:"amount"`
	Status string  `json:"status"`
}

type contextKey string

const userContextKey contextKey = "user"

// GetUserFromContext retrieves the authenticated user from the request context.
func GetUserFromContext(ctx context.Context) (*User, bool) {
	user, ok := ctx.Value(userContextKey).(*User)
	return user, ok
}

// OrderHandler handles GET requests for /orders/{id}
func OrderHandler(db *sql.DB) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodGet {
			http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
			return
		}

		// Extract the authenticated user from context (set by auth middleware)
		user, ok := GetUserFromContext(r.Context())
		if !ok || user == nil {
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		// Extract order ID from URL path: /orders/{id}
		pathParts := strings.Split(strings.TrimPrefix(r.URL.Path, "/"), "/")
		if len(pathParts) < 2 || pathParts[0] != "orders" || pathParts[1] == "" {
			http.Error(w, "Bad request: missing order ID", http.StatusBadRequest)
			return
		}

		orderID, err := strconv.ParseInt(pathParts[1], 10, 64)
		if err != nil {
			http.Error(w, "Bad request: invalid order ID", http.StatusBadRequest)
			return
		}

		// Query the database for the order using parameterized query to prevent SQL injection
		var order Order
		err = db.QueryRowContext(r.Context(),
			"SELECT id, user_id, item, amount, status FROM orders WHERE id = $1",
			orderID,
		).Scan(&order.ID, &order.UserID, &order.Item, &order.Amount, &order.Status)

		if err == sql.ErrNoRows {
			http.Error(w, "Order not found", http.StatusNotFound)
			return
		}
		if err != nil {
			http.Error(w, "Internal server error", http.StatusInternalServerError)
			return
		}

		// BROKEN ACCESS CONTROL PREVENTION:
		// Verify that the authenticated user owns this order, or is an admin.
		// Without this check, any authenticated user could access any order by
		// simply changing the order ID in the URL (IDOR vulnerability).
		if order.UserID != user.ID && user.Role != "admin" {
			// Return 403 Forbidden (not 404) so we don't leak info, but you could
			// also return 404 to avoid revealing that the order exists.
			http.Error(w, "Forbidden: you do not have access to this order", http.StatusForbidden)
			return
		}

		// Return the order as JSON
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		if err := json.NewEncoder(w).Encode(order); err != nil {
			http.Error(w, "Internal server error", http.StatusInternalServerError)
			return
		}
	}
}

